"use client";

import { useEffect, useState } from "react";

export default function PatientDashboard() {
  const [records, setRecords] = useState<any[]>([]);

  useEffect(() => {
    const fetchHistory = async () => {
      const user = JSON.parse(localStorage.getItem("user") || "{}");

      const res = await fetch(
        `http://localhost:5000/api/patient/${user.patientId}/history`,
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        }
      );

      const data = await res.json();
      setRecords(data);
    };

    fetchHistory();
  }, []);

  return (
    <div>
      <h1 className="text-xl font-bold mb-4">My Medical History</h1>

      <div className="space-y-4">
        {records.map((r, i) => (
          <div key={i} className="bg-white p-4 rounded shadow">
            <p><strong>Disease:</strong> {r.disease}</p>
            <p><strong>Hospital:</strong> {r.hospitalName}</p>
            <p><strong>Date:</strong> {new Date(r.date).toDateString()}</p>
          </div>
        ))}
      </div>
    </div>
  );
}